import{_ as e,o as n,c as s,a2 as t}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Arquitectura interna del log","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/kafka/09-arquitectura-interna-del-log.md","filePath":"data-engineering/kafka/09-arquitectura-interna-del-log.md","lastUpdated":1782521464000}'),o={name:"data-engineering/kafka/09-arquitectura-interna-del-log.md"};function i(r,a,l,c,p,d){return n(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="arquitectura-interna-del-log" tabindex="-1">Arquitectura interna del log <a class="header-anchor" href="#arquitectura-interna-del-log" aria-label="Permalink to &quot;Arquitectura interna del log&quot;">​</a></h1><p>Kafka esta construido alrededor de logs particionados. Un log es una secuencia append-only de registros ordenados por offset.</p><h2 id="log-segmentado" tabindex="-1">Log segmentado <a class="header-anchor" href="#log-segmentado" aria-label="Permalink to &quot;Log segmentado&quot;">​</a></h2><p>Cada partition se guarda como varios segmentos en disco.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders.created-0/</span></span>
<span class="line"><span>  00000000000000000000.log</span></span>
<span class="line"><span>  00000000000000000000.index</span></span>
<span class="line"><span>  00000000000000001000.log</span></span>
<span class="line"><span>  00000000000000001000.index</span></span></code></pre></div><p>Cuando un segmento alcanza cierto tamano o tiempo, Kafka abre otro.</p><h2 id="append-only" tabindex="-1">Append-only <a class="header-anchor" href="#append-only" aria-label="Permalink to &quot;Append-only&quot;">​</a></h2><p>Kafka escribe al final del log. Esto favorece I/O secuencial.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A[&quot;offset 0&quot;] --&gt; B[&quot;offset 1&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B --&gt; C[&quot;offset 2&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C --&gt; D[&quot;new writes append here&quot;]</span></span></code></pre></div><h2 id="indices" tabindex="-1">Indices <a class="header-anchor" href="#indices" aria-label="Permalink to &quot;Indices&quot;">​</a></h2><p>Kafka mantiene indices para localizar offsets dentro de segmentos sin recorrer todo el archivo.</p><h2 id="page-cache" tabindex="-1">Page cache <a class="header-anchor" href="#page-cache" aria-label="Permalink to &quot;Page cache&quot;">​</a></h2><p>Kafka se apoya mucho en la page cache del sistema operativo. Por eso memoria del host, disco y patrones de lectura importan tanto.</p><p>No todo &quot;uso de memoria&quot; implica problema: parte puede ser cache util del SO.</p><h2 id="zero-copy" tabindex="-1">Zero-copy <a class="header-anchor" href="#zero-copy" aria-label="Permalink to &quot;Zero-copy&quot;">​</a></h2><p>Kafka puede transferir datos desde disco a red de forma eficiente reduciendo copias entre espacio kernel y user space.</p><p>Esto ayuda mucho cuando consumidores leen eventos ya almacenados.</p><h2 id="retencion" tabindex="-1">Retencion <a class="header-anchor" href="#retencion" aria-label="Permalink to &quot;Retencion&quot;">​</a></h2><p>La retencion elimina segmentos completos cuando cumplen condiciones.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>retention.ms</span></span>
<span class="line"><span>retention.bytes</span></span></code></pre></div><p>Kafka no borra evento por evento en el caso normal; borra segmentos.</p><h2 id="compaction" tabindex="-1">Compaction <a class="header-anchor" href="#compaction" aria-label="Permalink to &quot;Compaction&quot;">​</a></h2><p>Con <code>cleanup.policy=compact</code>, Kafka conserva la ultima version por key.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key=user-1 value=A</span></span>
<span class="line"><span>key=user-1 value=B</span></span></code></pre></div><p>Tras compactacion, puede conservarse solo <code>B</code> para esa key.</p><h2 id="isr" tabindex="-1">ISR <a class="header-anchor" href="#isr" aria-label="Permalink to &quot;ISR&quot;">​</a></h2><p>ISR significa in-sync replicas: replicas suficientemente al dia con el leader.</p><p>Si una replica se queda atras, sale del ISR. Esto afecta disponibilidad de escrituras con <code>acks=all</code>.</p><h2 id="controller-y-metadata" tabindex="-1">Controller y metadata <a class="header-anchor" href="#controller-y-metadata" aria-label="Permalink to &quot;Controller y metadata&quot;">​</a></h2><p>El cluster necesita coordinar metadata:</p><ul><li>Brokers activos.</li><li>Leaders de partitions.</li><li>Configuracion de topics.</li><li>Estado de replicas.</li></ul><p>En Kafka moderno, esta coordinacion puede hacerse con KRaft en vez de ZooKeeper.</p><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Usa discos rapidos y monitoriza I/O.</li><li>Ajusta retencion segun reprocesamiento real.</li><li>Entiende compaction antes de usarla.</li><li>Monitoriza under-replicated partitions.</li><li>Evita eventos gigantes.</li><li>Dimensiona page cache y disco con margen.</li></ul>`,34)])])}const m=e(o,[["render",i]]);export{h as __pageData,m as default};
